server {
    listen 80 default_server;
    server_name craigmbrown.com www.craigmbrown.com 34.173.97.118 _;

    root /var/www/craigmbrown.com;
    index index.html index.htm;

    # Enable gzip compression
    gzip on;
    gzip_vary on;
    gzip_min_length 1024;
    gzip_types
        text/plain
        text/css
        text/xml
        text/javascript
        application/javascript
        application/xml+rss
        application/json;

    # Cache static assets
    location ~* \.(css|js|jpg|jpeg|png|gif|ico|svg)$ {
        expires 1y;
        add_header Cache-Control "public, immutable";
    }

    # Security headers
    add_header X-Frame-Options "SAMEORIGIN" always;
    add_header X-Content-Type-Options "nosniff" always;
    add_header X-XSS-Protection "1; mode=block" always;

    # Prevent CloudFlare from caching HTML pages
    location ~* \.html$ {
        add_header Cache-Control "no-cache, no-store, must-revalidate" always;
        add_header Pragma "no-cache" always;
        add_header Expires "0" always;
        add_header CF-Cache-Status "BYPASS" always;
    }

    # =====================================================
    # BlindOracle - Password Protected
    # =====================================================
    # =====================================================
    # BlindOracle Private - Password Protected
    # =====================================================
    location ^~ /blindoracle/private/ {
        auth_basic "BlindOracle Private";
        auth_basic_user_file /etc/nginx/.htpasswd_blindoracle;
        try_files $uri $uri/ =404;
    }

    location /blindoracle/ {
        # auth_basic "BlindOracle Dashboard";  # REMOVED - public landing page
        # auth_basic_user_file /etc/nginx/.htpasswd;  # REMOVED with auth_basic
        try_files $uri $uri/ =404;
    }

    location = /blindoracle {
        return 301 /blindoracle/;
    }

    # =====================================================
    # LLM Council Frontend - Password Protected
    # =====================================================
    location /llm-council/ {
        auth_basic "LLM Council";
        auth_basic_user_file /etc/nginx/.htpasswd;
        alias /var/www/craigmbrown.com/llm-council/;
        try_files $uri $uri/ /llm-council/index.html;
    }

    location = /llm-council {
        return 301 /llm-council/;
    }

    # =====================================================
    # TB Scout API - Consumer Monitoring Platform
    # =====================================================
    location /api/tb-scout/ {
        add_header Access-Control-Allow-Origin "*" always;
        add_header Access-Control-Allow-Methods "GET, POST, OPTIONS" always;
        add_header Access-Control-Allow-Headers "Content-Type" always;

        if ($request_method = 'OPTIONS') {
            add_header Access-Control-Allow-Origin "*";
            add_header Access-Control-Allow-Methods "GET, POST, OPTIONS";
            add_header Access-Control-Allow-Headers "Content-Type";
            return 204;
        }

        rewrite ^/api/tb-scout/(.*)$ /$1 break;
        proxy_pass http://127.0.0.1:5176;
        proxy_http_version 1.1;
        proxy_set_header Host $host;
        proxy_set_header X-Real-IP $remote_addr;
        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
        proxy_set_header X-Forwarded-Proto $scheme;
        proxy_read_timeout 300s;
        proxy_connect_timeout 75s;
    }

    # =====================================================
    # LLM Council API
    # =====================================================
    location /api/council/ {
        add_header Access-Control-Allow-Origin "*" always;
        add_header Access-Control-Allow-Methods "GET, POST, OPTIONS" always;
        add_header Access-Control-Allow-Headers "Content-Type" always;

        if ($request_method = 'OPTIONS') {
            add_header Access-Control-Allow-Origin "*";
            add_header Access-Control-Allow-Methods "GET, POST, OPTIONS";
            add_header Access-Control-Allow-Headers "Content-Type";
            return 204;
        }

        rewrite ^/api/council/(.*)$ /api/$1 break;
        proxy_pass http://127.0.0.1:8005;
        proxy_http_version 1.1;
        proxy_set_header Host $host;
        proxy_set_header X-Real-IP $remote_addr;
        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
        proxy_set_header X-Forwarded-Proto $scheme;
        proxy_read_timeout 300s;
        proxy_connect_timeout 75s;
    }

    # =====================================================
    # Static API Documentation
    # =====================================================
    location = /api-docs {
        return 302 /api-docs/;
    }

    location ^~ /api-docs/ {
        rewrite ^/api-docs/(.*)$ /marketplace/docs/$1 last;
    }

    location ^~ /marketplace/docs/ {
        add_header Cache-Control "no-cache, no-store, must-revalidate" always;
        try_files $uri $uri/ /marketplace/docs/index.html;
    }

    # =====================================================
    # Chainlink Marketplace API
    # =====================================================
    location ^~ /marketplace/ {
        add_header Access-Control-Allow-Origin "*" always;
        add_header Access-Control-Allow-Methods "GET, POST, PUT, DELETE, OPTIONS" always;
        add_header Access-Control-Allow-Headers "Authorization, Content-Type, X-API-Key" always;

        if ($request_method = 'OPTIONS') {
            add_header Access-Control-Allow-Origin "*";
            add_header Access-Control-Allow-Methods "GET, POST, PUT, DELETE, OPTIONS";
            add_header Access-Control-Allow-Headers "Authorization, Content-Type, X-API-Key";
            add_header Content-Length 0;
            add_header Content-Type "text/plain";
            return 204;
        }

        try_files $uri $uri/ @marketplace_api;
    }

    location @marketplace_api {
        rewrite ^/marketplace/(.*)$ /$1 break;
        proxy_pass http://127.0.0.1:8001;
        proxy_http_version 1.1;
        proxy_set_header Host $host;
        proxy_set_header X-Real-IP $remote_addr;
        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
        proxy_set_header X-Forwarded-Proto $scheme;
        proxy_set_header Connection "";
    }

    # =====================================================
    # Dashboards
    # =====================================================
    location /dashboards/ {
        try_files $uri $uri/ /dashboards/index.html;
    }

    location = /dashboards {
        return 301 /dashboards/;
    }

    # =====================================================
    # Onboarding API
    # =====================================================
    location /api/onboarding {
        add_header Access-Control-Allow-Origin "*" always;
        add_header Access-Control-Allow-Methods "GET, POST, OPTIONS" always;
        add_header Access-Control-Allow-Headers "Content-Type" always;

        if ($request_method = 'OPTIONS') {
            add_header Access-Control-Allow-Origin "*";
            add_header Access-Control-Allow-Methods "GET, POST, OPTIONS";
            add_header Access-Control-Allow-Headers "Content-Type";
            return 204;
        }

        proxy_pass http://34.58.12.50:8083/api/onboarding;
        proxy_http_version 1.1;
        proxy_set_header Host $host;
        proxy_set_header X-Real-IP $remote_addr;
        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
        proxy_set_header X-Forwarded-Proto $scheme;
        proxy_read_timeout 30s;
        proxy_connect_timeout 10s;
    }

    # Main location - prevent caching of index.html
    # =====================================================
    # BlindOracle x402 API - Reverse Proxy to thebaby VM
    # =====================================================
    location /api/v2/ {
        add_header Access-Control-Allow-Origin "*" always;
        add_header Access-Control-Allow-Methods "GET, POST, PUT, DELETE, OPTIONS" always;
        add_header Access-Control-Allow-Headers "Content-Type, X-Agent-Id, X-402-Payment, X-Payment-Rail" always;

        if ($request_method = "OPTIONS") {
            add_header Access-Control-Allow-Origin "*";
            add_header Access-Control-Allow-Methods "GET, POST, PUT, DELETE, OPTIONS";
            add_header Access-Control-Allow-Headers "Content-Type, X-Agent-Id, X-402-Payment, X-Payment-Rail";
            return 204;
        }

        rewrite ^/api/v2/(.*)$ /v2/$1 break;
        proxy_pass http://34.58.12.50:8402;
        proxy_http_version 1.1;
        proxy_set_header Host $host;
        proxy_set_header X-Real-IP $remote_addr;
        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
        proxy_set_header X-Forwarded-Proto $scheme;
        proxy_read_timeout 60s;
        proxy_connect_timeout 15s;
    }
    location / {
        add_header Cache-Control "no-cache, no-store, must-revalidate, max-age=0" always;
        add_header Pragma "no-cache" always;
        add_header Expires "Thu, 01 Jan 1970 00:00:00 GMT" always;
        add_header CDN-Cache-Control "no-store" always;
        add_header Cloudflare-CDN-Cache-Control "no-store" always;
        try_files $uri $uri/ =404;
    }

    # Explicit index.html with no-cache
    location = /index.html {
        add_header Cache-Control "no-cache, no-store, must-revalidate, max-age=0" always;
        add_header Pragma "no-cache" always;
        add_header Expires "Thu, 01 Jan 1970 00:00:00 GMT" always;
        add_header CDN-Cache-Control "no-store" always;
        add_header Cloudflare-CDN-Cache-Control "no-store" always;
    }

    # Error pages
    error_page 404 /index.html;
    error_page 500 502 503 504 /index.html;
}

